<?php
namespace App\Http\Controllers\Admin;use App\Http\Controllers\Controller;use App\Models\Brand;use Illuminate\Http\Request;use Illuminate\Support\Str;
class BrandController extends Controller{use HandlesAdminUploads;public function index(){return view('admin.crud.index',['title'=>'مدیریت برندها','items'=>Brand::orderBy('sort_order')->paginate(20),'route'=>'brands','columns'=>['name'=>'نام','is_active'=>'وضعیت']]);}public function create(){return view('admin.crud.form',['title'=>'برند','item'=>new Brand(),'route'=>'brands','fields'=>$this->fields()]);}public function store(Request $r){$d=$r->validate(['name'=>'required','slug'=>'nullable|unique:brands','description'=>'nullable','url'=>'nullable','sort_order'=>'nullable|integer','is_active'=>'nullable','show_in_home'=>'nullable','logo'=>'nullable|image|max:3072']);$d['slug']=$d['slug']?:Str::slug($d['name']);$d['logo']=$this->upload($r,'logo','brands');$d['is_active']=$r->boolean('is_active');$d['show_in_home']=$r->boolean('show_in_home');Brand::create($d);return redirect()->route('admin.brands.index')->with('success','ذخیره شد');}public function edit(Brand $brand){return view('admin.crud.form',['title'=>'برند','item'=>$brand,'route'=>'brands','fields'=>$this->fields()]);}public function update(Request $r,Brand $brand){$d=$r->validate(['name'=>'required','slug'=>'required|unique:brands,slug,'.$brand->id,'description'=>'nullable','url'=>'nullable','sort_order'=>'nullable|integer','is_active'=>'nullable','show_in_home'=>'nullable','logo'=>'nullable|image|max:3072']);$d['logo']=$this->upload($r,'logo','brands',$brand->logo);$d['is_active']=$r->boolean('is_active');$d['show_in_home']=$r->boolean('show_in_home');$brand->update($d);return redirect()->route('admin.brands.index')->with('success','به‌روزرسانی شد');}public function destroy(Brand $brand){$brand->delete();return back();}private function fields(){return ['name'=>'text','slug'=>'text','logo'=>'file','description'=>'textarea','url'=>'text','sort_order'=>'number','show_in_home'=>'checkbox','is_active'=>'checkbox'];}}
